import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  // Scroll effect to change appearance
  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'Electronics', path: '/electronics' },
    { name: 'Electrical', path: '/electrical' },
    { name: 'Chemical', path: '/chemical' },
    { name: 'Industries', path: '/industries' },
    { name: 'About Us', path: '/about' },
    { name: 'Careers', path: '/careers' },
  ];

  return (
    <nav 
      className={`fixed w-full z-[100] top-0 left-0 transition-all duration-500 ${
        scrolled 
          ? 'py-3 bg-white/80 backdrop-blur-lg shadow-[0_8px_30px_rgb(0,0,0,0.04)] border-b border-gray-100' 
          : 'py-6 bg-transparent'
      }`}
    >
      <div className="max-w-[1440px] mx-auto px-6 md:px-12">
        <div className="flex justify-between items-center h-16">

          {/* 1. LOGO AREA */}
          <div className="flex-shrink-0">
            <Link to="/" className="group flex items-center gap-1">
              <span className="text-3xl font-[900] text-[#1C1C1C] tracking-tighter transition-transform duration-300 group-hover:scale-105">
                HUDSON
              </span>
              <span className="h-2.5 w-2.5 rounded-full bg-orange-600 animate-pulse mt-3"></span>
            </Link>
          </div>

          {/* 2. DESKTOP NAV (Floating Style) */}
          <div className="hidden lg:flex items-center bg-gray-100/50 backdrop-blur-md px-2 py-1.5 rounded-full border border-gray-200/50">
            {navLinks.map((link) => {
              const isActive = location.pathname === link.path;
              return (
                <Link
                  key={link.name}
                  to={link.path}
                  className={`relative px-5 py-2 text-[14px] font-bold tracking-tight transition-all duration-300 rounded-full ${
                    isActive 
                      ? 'text-white bg-orange-600 shadow-lg shadow-orange-200' 
                      : 'text-gray-600 hover:text-orange-600'
                  }`}
                >
                  {link.name}
                </Link>
              );
            })}
          </div>

          {/* 3. RIGHT ACTIONS */}
          <div className="hidden md:flex items-center gap-3">
            <button className="text-gray-900 font-bold px-6 py-2.5 rounded-full hover:bg-gray-100 transition-all text-sm uppercase tracking-wider">
              Login
            </button>
            <button className="relative overflow-hidden group bg-gray-950 text-white px-7 py-3 rounded-full font-bold text-sm transition-all hover:shadow-2xl hover:shadow-orange-200 active:scale-95">
              <span className="relative z-10 uppercase tracking-widest">Let's Talk</span>
              <div className="absolute inset-0 bg-gradient-to-r from-orange-500 to-orange-600 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
            </button>
          </div>

          {/* 4. MOBILE TOGGLE */}
          <div className="lg:hidden">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className={`p-2 rounded-full transition-all ${isOpen ? 'bg-orange-600 text-white' : 'bg-gray-100 text-gray-900'}`}
            >
              <div className="w-6 h-6 flex flex-col justify-center items-center gap-1.5">
                <span className={`h-0.5 w-5 bg-current transition-all ${isOpen ? 'rotate-45 translate-y-2' : ''}`}></span>
                <span className={`h-0.5 w-5 bg-current transition-all ${isOpen ? 'opacity-0' : ''}`}></span>
                <span className={`h-0.5 w-5 bg-current transition-all ${isOpen ? '-rotate-45 -translate-y-2' : ''}`}></span>
              </div>
            </button>
          </div>
        </div>
      </div>

      {/* 5. MOBILE MENU (Full Screen Overlay Style) */}
      <div className={`fixed inset-0 bg-white z-[-1] transition-all duration-500 lg:hidden ${isOpen ? 'translate-y-0 opacity-100' : '-translate-y-full opacity-0'}`}>
        <div className="flex flex-col h-full pt-32 px-8">
          <div className="space-y-4">
            {navLinks.map((link, i) => (
              <Link
                key={link.name}
                to={link.path}
                onClick={() => setIsOpen(false)}
                className="block text-4xl font-black text-gray-900 hover:text-orange-600 transition-all tracking-tighter"
                style={{ transitionDelay: `${i * 50}ms` }}
              >
                {link.name}
              </Link>
            ))}
          </div>

          <div className="mt-auto pb-12 space-y-4">
             <div className="h-px w-full bg-gray-100 mb-8"></div>
             <p className="text-gray-400 text-sm uppercase tracking-[0.2em] font-bold">Get in touch</p>
             <h3 className="text-2xl font-bold text-gray-900">hello@hudson.com</h3>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
